/**
 * Source Screener — Layer 2 of the 5-layer fallback strategy
 *
 * When a route is registered without validate(), nodox inspects each
 * middleware function's source code as a string (.toString()) looking for
 * patterns that indicate the function uses Zod or Joi.
 *
 * Functions that match are "flagged" for the targeted dry-run (Layer 3).
 * Functions that don't match are ignored — no dry-run cost.
 *
 * Known limitation: this layer breaks under bundlers/minifiers.
 * If the dev server runs through Babel, SWC, esbuild, or tsc, function
 * source is mangled and patterns won't match. In that case, use validate().
 */

/**
 * Patterns indicating a function uses Zod or Joi for validation.
 * Tested against the compressed (whitespace-removed) function source.
 */
const ZOD_PATTERNS = [
  /\.safeParse\(/,
  /\.parseAsync\(/,
  /\.safeParseAsync\(/,
  /\bz\.(object|string|number|boolean|array|union|enum)\b/,
  /_zod\.z\./,           // transpiled: import * as _zod from 'zod'
  /zod_1\.z\./,          // commonjs transpiled by tsc
  /[a-zA-Z]{2,}\.parse\(/,        // Catch anyVariable.parse() — excludes single-char (valibot's v.parse)
  /[a-zA-Z]{2,}\.safeParse\(/,    // Catch anyVariable.safeParse() — excludes single-char
  // Catch any variableName.parse(req.*) — the most common validation pattern.
  /\.parse\(req[.,\s)]/,
  /\w+[Ss]chema\.parse\(/,
  /\w+[Vv]alidator\.parse\(/,
]

const JOI_PATTERNS = [
  /\.validate\(req\b/,
  /\.validate\(\w+\.body\b/, // Catch schema.validate(req.body)
  /joi\.(object|string|number|boolean|array)\(/,
  /_joi\.(default|joi)\b/i,
  /Joi\.(object|string|number|boolean|array)\(/,
]

const YUP_PATTERNS = [
  /yup\.(object|string|number|boolean|array|mixed)\(/,
  /\.validateSync\(req\b/,
  /\.validateSync\(req\.body\b/,
  /yup_1\.(object|string|number|boolean)/, // tsc-transpiled yup
  /schema\.validateSync\b/,
]

// Valibot uses a functional API (parse(schema, data)) rather than the instance-method
// API (schema.parse(data)) that our dry-run interceptor relies on. Flagging valibot
// handlers for dry-run is wasted work — the dry-run never captures anything useful.
// Valibot routes are covered by live observation (req.body / res.json interception).
const VALIBOT_PATTERNS = []

// TypeBox uses Value.Check / Value.Parse from @sinclair/typebox/value.
// Flagging for dry-run is not useful — TypeBox validation is functional and won't
// be captured by the schema-patcher. Covered by live observation instead.
const TYPEBOX_PATTERNS = []

/**
 * Known non-validator function names — exact matches are skipped with zero
 * source-inspection cost. Covers Express built-ins, popular npm middleware,
 * and nodox's own internals.
 */
const KNOWN_NON_VALIDATORS = new Set([
  // Express built-ins and internal names
  'router', 'bound dispatch', 'bound ',
  'jsonParser', 'urlencodedParser', 'rawParser', 'textParser',
  'json', 'urlencoded', 'raw', 'text', 'query',
  'init', 'expressInit',

  // nodox's own middleware
  'nodoxMiddleware', 'nodoxValidateMiddleware', 'responseInterceptorMiddleware',
  'uiHandler',

  // Security & utility middleware
  'corsMiddleware', 'cors', 'corsPreflight',
  'helmet',
  'morgan', 'logger', 'accessLogger', 'requestLogger',
  'compression',
  'responseTime',
  'timeout', 'connectTimeout',
  'methodOverride',

  // Rate limiting
  'rateLimit', 'slowDown', 'expressRateLimit',

  // Auth & sessions
  'session', 'expressSession', 'cookieParser', 'cookieSession',
  'passport', 'initialize', 'passportInitialize', 'passportSession',
  'authenticate', 'jwtMiddleware', 'bearerStrategy',

  // File upload
  'multer', 'upload', 'single', 'array', 'fields', 'none', 'any',
  'busboy', 'multipart',

  // Caching
  'cache', 'apicache', 'expressCache',

  // Body parsing
  'bodyParser',

  // Static file serving
  'serveStatic', 'staticMiddleware', 'sendFile',

  // Error handling
  'errorHandler', 'notFound', 'notFoundHandler',
  'finalhandler',

  // Validation frameworks (not the user's validators — these are factory wrappers)
  'checkSchema', 'check', 'param', 'query', 'header', 'cookie', 'validationResult',

  // Logging
  'pinoHttp', 'winstonMiddleware',

  // Misc popular middleware
  'device', 'userAgent', 'responseCompression',
  'requestId', 'correlationId',
  'i18n', 'locale',
])

/**
 * Source-code signatures that indicate a function came from a bundled/transpiled
 * node_modules package rather than user-written code. These are CommonJS interop
 * artifacts generated by TypeScript, Babel, esbuild, webpack, and similar tools.
 *
 * User code almost never contains these patterns; npm packages almost always do
 * (unless they ship native ESM, which won't have these signatures either).
 */
const NODE_MODULES_SOURCE_PATTERNS = [
  /Object\.defineProperty\(exports,\s*["']__esModule["']/,  // TypeScript/Babel CJS
  /exports\.__esModule\s*=\s*true/,                          // TS simple CJS interop
  /__webpack_require__\(/,                                   // Webpack bundle
  /\/\*\*\s*@license\b/,                                     // License JSDoc comment
  /\/\*\s*!\s*Copyright\s/i,                                 // Minified copyright comment
  /function\s*\(\s*module\s*,\s*exports\s*,\s*__webpack/,   // Webpack factory
]

/**
 * Detect if a function's source code shows it is a bundled/transpiled npm package.
 * @param {string} src - fn.toString() output
 * @returns {boolean}
 */
function isLikelyNodeModuleCode(src) {
  return NODE_MODULES_SOURCE_PATTERNS.some(p => p.test(src))
}

/**
 * Check whether a middleware function looks like it uses a schema validator.
 * @param {Function} fn
 * @returns {boolean}
 */
export function looksLikeValidator(fn) {
  if (typeof fn !== 'function') return false

  // Skip known non-validators by name first — zero cost
  const name = fn.name || ''
  if (KNOWN_NON_VALIDATORS.has(name)) return false

  // Skip nodox's own middleware (marked at creation time)
  if (fn.__isNodoxValidate) return false

  let src
  try {
    src = fn.toString()
  } catch {
    return false
  }

  // Too short to contain a meaningful validator call
  if (src.length < 20) return false

  // Minification detector: long source with no whitespace formatting is likely minified
  if (src.length > 500 && !src.includes('\n') && !src.includes('  ')) {
    return false
  }

  // Callsite-based exclusion: reject functions that look like bundled npm packages.
  // These are CJS interop artifacts that appear in published packages, not user code.
  if (isLikelyNodeModuleCode(src)) return false

  // Remove whitespace for more reliable pattern matching
  const compressed = src.replace(/\s+/g, '')

  return ZOD_PATTERNS.some(p => p.test(compressed)) ||
         JOI_PATTERNS.some(p => p.test(compressed)) ||
         YUP_PATTERNS.some(p => p.test(compressed)) ||
         VALIBOT_PATTERNS.some(p => p.test(compressed)) ||
         TYPEBOX_PATTERNS.some(p => p.test(compressed))
}

/**
 * Scan a list of route handlers and return those that look like validators.
 * @param {Function[]} handlers
 * @returns {Function[]}
 */
export function flagValidatorsInHandlers(handlers) {
  return handlers.filter(looksLikeValidator)
}
